package main

import (
	"fmt"
	"net/http"
	"net/url"
	"sync"
	"time"

	"github.com/gofiber/fiber/v2"
)

// WebhookConfigRequest represents the incoming request body
type WebhookConfigRequest struct {
	WebhookURL string `json:"webhook_url"`
}

// Response represents the JSON response structure
type Response struct {
	Success bool   `json:"success"`
	Message string `json:"message"`
}

// savedConfig stores the configured webhook URL with thread safety
var savedConfig struct {
	sync.RWMutex
	webhookURL string
}

// ConfigureWebhook handles the webhook configuration request
func ConfigureWebhook(ctx *fiber.Ctx) error {
	var req WebhookConfigRequest

	// Parse request body
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(Response{
			Success: false,
			Message: fmt.Sprintf("Failed to parse request body: %v", err),
		})
	}

	// Validate required field
	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(Response{
			Success: false,
			Message: "webhook_url is required",
		})
	}

	// Validate URL format (must be absolute)
	if _, err := url.ParseRequestURI(req.WebhookURL); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(Response{
			Success: false,
			Message: fmt.Sprintf("Invalid webhook URL format: %v", err),
		})
	}

	// Create HTTP client with 3-second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Send test GET request to validate webhook
	resp, err := client.Get(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(Response{
			Success: false,
			Message: fmt.Sprintf("Webhook validation failed: %v", err),
		})
	}
	defer resp.Body.Close()

	// Check for successful response status (2xx)
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusBadRequest).JSON(Response{
			Success: false,
			Message: fmt.Sprintf("Webhook returned non-success status code: %d", resp.StatusCode),
		})
	}

	// Save the valid webhook configuration (thread-safe)
	savedConfig.Lock()
	savedConfig.webhookURL = req.WebhookURL
	savedConfig.Unlock()

	// Return success response
	return ctx.JSON(Response{
		Success: true,
		Message: "Webhook configured successfully",
	})
}

func main() {
	// Initialize Fiber app
	app := fiber.New()

	// Register the configure webhook endpoint
	app.Post("/configure-webhook", ConfigureWebhook)

	// Start server on port 3000
	app.Listen(":3000")
}

