// savedWebhookURL stores the configured webhook URL (global for demo purposes)
var savedWebhookURL string

// ConfigureWebhookRequest represents the incoming request body
type ConfigureWebhookRequest struct {
	WebhookURL string `json:"webhook_url"`
}

// WebhookResponse represents the response returned to the client
type WebhookResponse struct {
	Success bool   `json:"success"`
	Message string `json:"message"`
	URL     string `json:"url,omitempty"`
}

// ConfigureWebhook handles the webhook configuration request
func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Parse the request body into the struct
	var req ConfigureWebhookRequest
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookResponse{
			Success: false,
			Message: fmt.Sprintf("failed to parse request body: %v", err),
		})
	}

	// Validate that webhook_url is provided
	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookResponse{
			Success: false,
			Message: "webhook_url is a required field",
		})
	}

	// Create an HTTP client with 3-second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Send a test GET request to validate the webhook URL
	resp, err := client.Get(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookResponse{
			Success: false,
			Message: fmt.Sprintf("failed to validate webhook URL: %v", err),
			URL:     req.WebhookURL,
		})
	}
	defer resp.Body.Close() // Ensure the response body is closed

	// Check if the response status code is in the 2xx range
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookResponse{
			Success: false,
			Message: fmt.Sprintf("webhook URL returned non-success status code: %d", resp.StatusCode),
			URL:     req.WebhookURL,
		})
	}

	// Save the validated webhook URL
	savedWebhookURL = req.WebhookURL

	// Return success response
	return ctx.JSON(WebhookResponse{
		Success: true,
		Message: "webhook configured successfully",
		URL:     savedWebhookURL,
	})
}

func main() {
	// Initialize Fiber app
	app := fiber.New()

	// Register the POST route for webhook configuration
	app.Post("/configure-webhook", ConfigureWebhook)

	// Start the server on port 3000
	log.Println("Server starting on :3000")
	log.Fatal(app.Listen(":3000"))
}

