var forbiddenNets = []net.IPNet{
	// IPv4 loopback: 127.0.0.0/8
	{IP: net.ParseIP("127.0.0.0"), Mask: net.CIDRMask(8, 32)},
	// IPv4 private network: 10.0.0.0/8
	{IP: net.ParseIP("10.0.0.0"), Mask: net.CIDRMask(8, 32)},
	// IPv4 private network: 172.16.0.0/12
	{IP: net.ParseIP("172.16.0.0"), Mask: net.CIDRMask(12, 32)},
	// IPv4 private network: 192.168.0.0/16
	{IP: net.ParseIP("192.168.0.0"), Mask: net.CIDRMask(16, 32)},
	// IPv4 link-local: 169.254.0.0/16
	{IP: net.ParseIP("169.254.0.0"), Mask: net.CIDRMask(16, 32)},
	// IPv6 loopback: ::1/128
	{IP: net.ParseIP("::1"), Mask: net.CIDRMask(128, 128)},
	// IPv6 unique local address: fc00::/7
	{IP: net.ParseIP("fc00::"), Mask: net.CIDRMask(7, 128)},
	// IPv6 link-local: fe80::/10
	{IP: net.ParseIP("fe80::"), Mask: net.CIDRMask(10, 128)},
}

// isForbiddenIP checks if an IP address is in a forbidden network
func isForbiddenIP(ip net.IP) bool {
	for _, n := range forbiddenNets {
		if n.Contains(ip) {
			return true
		}
	}
	return false
}

// validateWebhookURL performs comprehensive validation on a webhook URL
func validateWebhookURL(u string) error {
	parsedURL, err := url.ParseRequestURI(u)
	if err != nil {
		return err
	}

	// Validate scheme
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return fmt.Errorf("must use http or https scheme")
	}

	// Check for user info (e.g., http://user:pass@example.com)
	if parsedURL.User != nil {
		return fmt.Errorf("must not contain user info")
	}

	// Validate port (only allow 80 for http, 443 for https)
	port := parsedURL.Port()
	if port != "" && port != "80" && port != "443" {
		return fmt.Errorf("must use port 80 (http) or 443 (https)")
	}

	// Resolve hostname to IP addresses
	hostname := parsedURL.Hostname()
	ips, err := net.LookupIP(hostname)
	if err != nil {
		return fmt.Errorf("failed to resolve host: %w", err)
	}

	// Check each resolved IP against forbidden networks
	for _, ip := range ips {
		if isForbiddenIP(ip) {
			return fmt.Errorf("resolves to a forbidden IP address")
		}
	}

	return nil
}

// ConfigureWebhook handles POST requests to configure a webhook URL
func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Parse the JSON request body
	var req webhookRequest
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Invalid JSON format",
		})
	}

	// Validate that webhook_url is provided
	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook_url is required",
		})
	}

	// Perform comprehensive webhook URL validation
	if err := validateWebhookURL(req.WebhookURL); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   fmt.Sprintf("Invalid webhook URL: %v", err),
		})
	}

	// Create a custom HTTP client with timeout and redirect validation
	client := &http.Client{
		Timeout: 3 * time.Second,
		CheckRedirect: func(req *http.Request, via []*http.Request) error {
			// Limit number of redirects to prevent loops
			if len(via) >= 10 {
				return fmt.Errorf("too many redirects")
			}
			// Validate each redirect URL
			if err := validateWebhookURL(req.URL.String()); err != nil {
				return fmt.Errorf("invalid redirect: %w", err)
			}
			return nil
		},
	}

	// Send test GET request to webhook URL (as per requirements)
	resp, err := client.Get(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   fmt.Sprintf("Failed to send test request to webhook URL: %v", err),
		})
	}
	defer resp.Body.Close()

	// Check if the webhook responded with a 2xx status code
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   fmt.Sprintf("Webhook URL returned non-success status: %d", resp.StatusCode),
		})
	}

	// Save the configuration (placeholder for actual database operation)
	// db.SaveWebhookURL(req.WebhookURL)

	// Return success response
	return ctx.Status(fiber.StatusOK).JSON(fiber.Map{
		"success": true,
		"message": "Webhook configured successfully",
	})
}

