type WebhookRequest struct {
	WebhookURL string `json:"webhook_url"`
}

// WebhookResponse represents the outgoing response
type WebhookResponse struct {
	Success bool   `json:"success"`
	Message string `json:"message,omitempty"`
	Error   string `json:"error,omitempty"`
}

// savedWebhookURL stores the configured webhook URL (in-memory storage for this example)
var savedWebhookURL string

// ConfigureWebhook handles the webhook configuration request
func ConfigureWebhook(ctx *fiber.Ctx) error {
	var req WebhookRequest
	// Parse request body
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookResponse{
			Success: false,
			Error:   "Invalid request body: " + err.Error(),
		})
	}

	// Validate required field
	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookResponse{
			Success: false,
			Error:   "webhook_url is required",
		})
	}

	// Parse and validate URL format
	parsedURL, err := url.Parse(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookResponse{
			Success: false,
			Error:   "Invalid webhook URL: " + err.Error(),
		})
	}

	// Ensure URL uses HTTP/HTTPS scheme
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookResponse{
			Success: false,
			Error:   "Webhook URL must use http or https scheme",
		})
	}

	// Create HTTP client with 3-second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Create test GET request
	testReq, err := http.NewRequest("GET", req.WebhookURL, nil)
	if err != nil {
		return ctx.Status(fiber.StatusInternalServerError).JSON(WebhookResponse{
			Success: false,
			Error:   "Failed to create test request: " + err.Error(),
		})
	}

	// Send test request
	resp, err := client.Do(testReq)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookResponse{
			Success: false,
			Error:   "Failed to send test request: " + err.Error(),
		})
	}
	// Ensure response body is closed
	defer resp.Body.Close()

	// Save the valid webhook URL
	savedWebhookURL = req.WebhookURL

	// Return success response
	return ctx.JSON(WebhookResponse{
		Success: true,
		Message: "Webhook configured successfully",
	})
}

func main() {
	// Create Fiber app
	app := fiber.New()

	// Register the ConfigureWebhook handler
	app.Post("/configure-webhook", ConfigureWebhook)

	// Start server on port 3000
	log.Fatal(app.Listen(":3000"))
}

