package main

import (
	"context"
	"encoding/json"
	"fmt"
	"io"
	"net"
	"net/http"
	"net/url"
	"time"

	"github.com/gofiber/fiber/v2"
)

// webhookRequest represents the expected JSON request body
type webhookRequest struct {
	WebhookURL string `json:"webhook_url"`
}

// isReservedIP checks if an IP address is in a reserved range (loopback, private, link-local)
func isReservedIP(ip net.IP) bool {
	if ip == nil {
		return true
	}
	return ip.IsLoopback() || ip.IsPrivate() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast()
}

// ConfigureWebhook handles POST requests to configure a webhook URL
func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Parse the JSON request body
	var req webhookRequest
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Invalid JSON format",
		})
	}

	// Validate that webhook_url is provided
	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook_url is required",
		})
	}

	// Validate URL format
	parsedURL, err := url.ParseRequestURI(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Invalid webhook URL format",
		})
	}

	// Ensure the URL has a valid scheme
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook URL must use http or https scheme",
		})
	}

	// Block URLs with user credentials
	if parsedURL.User != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook URL must not contain user credentials",
		})
	}

	// Create custom HTTP client with SSRF protection and timeout
	transport := &http.Transport{
		DialContext: func(dialCtx context.Context, network, addr string) (net.Conn, error) {
			// Split host and port (handle cases without port)
			host, _, err := net.SplitHostPort(addr)
			if err != nil {
				host = addr
			}

			// Resolve host to IP addresses
			ips, err := net.DefaultResolver.LookupIP(dialCtx, "ip", host)
			if err != nil {
				return nil, err
			}

			// Check each IP against reserved ranges
			for _, ip := range ips {
				if isReservedIP(ip) {
					return nil, fmt.Errorf("reserved IP address not allowed")
				}
			}

			// Proceed with dialing
			dialer := &net.Dialer{}
			return dialer.DialContext(dialCtx, network, addr)
		},
	}

	client := &http.Client{
		Timeout:   3 * time.Second,
		Transport: transport,
	}

	// Create test GET request with propagated context
	reqTest, err := http.NewRequestWithContext(ctx.Context(), http.MethodGet, req.WebhookURL, nil)
	if err != nil {
		return ctx.Status(fiber.StatusInternalServerError).JSON(fiber.Map{
			"success": false,
			"error":   "Failed to create test request",
		})
	}

	// Send test request
	resp, err := client.Do(reqTest)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   fmt.Sprintf("Failed to send test request: %v", err),
		})
	}
	defer resp.Body.Close()

	// Check for successful response status (2xx)
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   fmt.Sprintf("Webhook URL returned non-success status: %d", resp.StatusCode),
		})
	}

	// Read and discard up to 1MB of response body to enable connection reuse and prevent abuse
	_, _ = io.Copy(io.Discard, io.LimitReader(resp.Body, 1<<20))

	// Save the configuration (placeholder)
	// db.SaveWebhookURL(req.WebhookURL)

	// Return success response
	return ctx.Status(fiber.StatusOK).JSON(fiber.Map{
		"success": true,
		"message": "Webhook configured successfully",
	})
}

