package main

import (
	"net/http"
	"net/url"
	"time"

	"github.com/gofiber/fiber/v2"
)

// savedWebhookURL stores the configured webhook URL (in-memory storage for demonstration)
var savedWebhookURL string

// WebhookConfigRequest represents the incoming request body
type WebhookConfigRequest struct {
	WebhookURL string `json:"webhook_url"`
}

// WebhookConfigResponse represents the JSON response
type WebhookConfigResponse struct {
	Success bool   `json:"success"`
	Message string `json:"message"`
	Error   string `json:"error,omitempty"`
}

// ConfigureWebhook handles the webhook configuration request
func ConfigureWebhook(ctx *fiber.Ctx) error {
	var req WebhookConfigRequest
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookConfigResponse{
			Success: false,
			Message: "Invalid request body",
			Error:   err.Error(),
		})
	}

	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookConfigResponse{
			Success: false,
			Message: "webhook_url is required",
		})
	}

	// Validate URL format
	if _, err := url.ParseRequestURI(req.WebhookURL); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookConfigResponse{
			Success: false,
			Message: "Invalid webhook URL format",
			Error:   err.Error(),
		})
	}

	// Create HTTP client with 3-second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Send test GET request
	resp, err := client.Get(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookConfigResponse{
			Success: false,
			Message: "Failed to send test request to webhook URL",
			Error:   err.Error(),
		})
	}
	defer resp.Body.Close()

	// Save the webhook configuration
	savedWebhookURL = req.WebhookURL

	return ctx.JSON(WebhookConfigResponse{
		Success: true,
		Message: "Webhook configured successfully",
	})
}

func main() {
	app := fiber.New()

	// Register the configure webhook route
	app.Post("/configure-webhook", ConfigureWebhook)

	// Start server on port 3000
	app.Listen(":3000")
}

