package main

import (
	"net/http"
	"sync"
	"time"

	"github.com/gofiber/fiber/v2"
)

var (
	savedWebhookURL string
	webhookMutex    sync.RWMutex
)

type WebhookConfigRequest struct {
	WebhookURL string `json:"webhook_url"`
}

type APIResponse struct {
	Success bool        `json:"success"`
	Message string      `json:"message"`
	Data    interface{} `json:"data,omitempty"`
}

func ConfigureWebhook(ctx *fiber.Ctx) error {
	var req WebhookConfigRequest
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(APIResponse{
			Success: false,
			Message: "Invalid request body",
		})
	}

	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(APIResponse{
			Success: false,
			Message: "webhook_url is required",
		})
	}

	// Create HTTP client with 3-second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Send test GET request to validate the webhook URL
	resp, err := client.Get(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(APIResponse{
			Success: false,
			Message: "Failed to validate webhook URL: " + err.Error(),
		})
	}
	defer resp.Body.Close()

	// Check if the response status code is successful (2xx)
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusBadRequest).JSON(APIResponse{
			Success: false,
			Message: "Webhook URL returned non-success status: " + resp.Status,
		})
	}

	// Save the valid webhook URL with thread-safe access
	webhookMutex.Lock()
	savedWebhookURL = req.WebhookURL
	webhookMutex.Unlock()

	// Return success response
	return ctx.JSON(APIResponse{
		Success: true,
		Message: "Webhook configured successfully",
		Data: map[string]string{
			"webhook_url": savedWebhookURL,
		},
	})
}

func main() {
	app := fiber.New()

	// Register the configure webhook endpoint
	app.Post("/configure-webhook", ConfigureWebhook)

	// Start the server on port 3000
	app.Listen(":3000")
}

