)

// WebhookConfig represents the incoming request body
type WebhookConfig struct {
	WebhookURL string `json:"webhook_url"`
}

// savedConfig holds the latest valid configuration (in-memory for this example)
var savedConfig *WebhookConfig

func ConfigureWebhook(ctx *fiber.Ctx) error {
	var req WebhookConfig
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(http.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Invalid request body: " + err.Error(),
		})
	}

	if req.WebhookURL == "" {
		return ctx.Status(http.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook_url is required",
		})
	}

	// Validate the URL by sending a GET request with 3s timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	testResp, err := client.Get(req.WebhookURL)
	if err != nil {
		return ctx.Status(http.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Failed to validate webhook URL: " + err.Error(),
		})
	}
	defer testResp.Body.Close()

	// Save the valid configuration
	savedConfig = &req

	return ctx.Status(http.StatusOK).JSON(fiber.Map{
		"success": true,
		"message": "Webhook configured successfully",
	})
}

