package main

import (
	"net/http"
	"net/url"
	"sync"
	"time"

	"github.com/gofiber/fiber/v2"
)

// WebhookConfigRequest represents the incoming request body for webhook configuration
type WebhookConfigRequest struct {
	WebhookURL string `json:"webhook_url"`
}

// WebhookResponse represents the JSON response for webhook configuration
type WebhookResponse struct {
	Success bool   `json:"success"`
	Message string `json:"message"`
}

var (
	// savedWebhookURL stores the configured webhook URL (in-memory for example)
	savedWebhookURL string
	// webhookMutex protects access to savedWebhookURL for concurrent access
	webhookMutex sync.RWMutex
)

// ConfigureWebhook handles the webhook configuration POST request
func ConfigureWebhook(ctx *fiber.Ctx) error {
	var req WebhookConfigRequest

	// Parse the JSON request body
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookResponse{
			Success: false,
			Message: "Invalid request body: " + err.Error(),
		})
	}

	// Check if webhook_url is provided
	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookResponse{
			Success: false,
			Message: "webhook_url is required",
		})
	}

	// Validate URL format and scheme
	parsedURL, err := url.ParseRequestURI(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookResponse{
			Success: false,
			Message: "Invalid webhook URL format: " + err.Error(),
		})
	}

	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookResponse{
			Success: false,
			Message: "Webhook URL must use http or https scheme",
		})
	}

	// Create HTTP client with 3-second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Send test GET request to validate the webhook URL
	resp, err := client.Get(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusOK).JSON(WebhookResponse{
			Success: false,
			Message: "Failed to validate webhook URL: " + err.Error(),
		})
	}
	// Ensure response body is closed to prevent resource leaks
	defer resp.Body.Close()

	// Save the valid webhook URL with mutex protection
	webhookMutex.Lock()
	savedWebhookURL = req.WebhookURL
	webhookMutex.Unlock()

	// Return success response
	return ctx.Status(fiber.StatusOK).JSON(WebhookResponse{
		Success: true,
		Message: "Webhook configured successfully",
	})
}

func main() {
	// Create a new Fiber instance
	app := fiber.New()

	// Register the webhook configuration route
	app.Post("/webhook/configure", ConfigureWebhook)

	// Optional: Route to check the currently configured webhook (for testing)
	app.Get("/webhook/current", func(ctx *fiber.Ctx) error {
		webhookMutex.RLock()
		defer webhookMutex.RUnlock()

		if savedWebhookURL == "" {
			return ctx.JSON(fiber.Map{
				"success": false,
				"message": "No webhook configured yet",
			})
		}

		return ctx.JSON(fiber.Map{
			"success":     true,
			"webhook_url": savedWebhookURL,
		})
	})

	// Start the server on port 3000
	if err := app.Listen(":3000"); err != nil {
		panic("Failed to start server: " + err.Error())
	}
}

