package main

import (
	"net/http"
	"time"

	"github.com/gofiber/fiber/v2"
)

// WebhookConfigRequest represents the incoming request body for configuring a webhook
type WebhookConfigRequest struct {
	WebhookURL string `json:"webhook_url"`
}

// WebhookResponse represents the JSON response for the webhook configuration endpoint
type WebhookResponse struct {
	Status   string `json:"status"`
	Message  string `json:"message"`
	SavedURL string `json:"saved_url,omitempty"`
}

// currentWebhookURL stores the last successfully configured webhook URL (in-memory storage)
var currentWebhookURL string

// ConfigureWebhook handles the POST request to configure and validate a webhook URL
func ConfigureWebhook(ctx *fiber.Ctx) error {
	var req WebhookConfigRequest

	// Parse incoming JSON request body
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookResponse{
			Status:  "error",
			Message: "Failed to parse request body: " + err.Error(),
		})
	}

	// Validate required field
	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookResponse{
			Status:  "error",
			Message: "webhook_url is a required field",
		})
	}

	// Create HTTP client with 3-second timeout as required
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Create test GET request using the fiber context for cancellation propagation
	testReq, err := http.NewRequestWithContext(ctx.Context(), http.MethodGet, req.WebhookURL, nil)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookResponse{
			Status:  "error",
			Message: "Invalid webhook URL format: " + err.Error(),
		})
	}

	// Execute test request
	resp, err := client.Do(testReq)
	if err != nil {
		return ctx.Status(fiber.StatusUnprocessableEntity).JSON(WebhookResponse{
			Status:  "error",
			Message: "Webhook validation failed: " + err.Error(),
		})
	}
	// Ensure response body is closed to prevent resource leaks
	defer resp.Body.Close()

	// Save the validated webhook URL (in-memory for this example)
	currentWebhookURL = req.WebhookURL

	// Return success response
	return ctx.Status(fiber.StatusOK).JSON(WebhookResponse{
		Status:   "success",
		Message:  "Webhook configured and validated successfully",
		SavedURL: currentWebhookURL,
	})
}

func main() {
	// Initialize Fiber app
	app := fiber.New()

	// Register the webhook configuration endpoint
	app.Post("/configure-webhook", ConfigureWebhook)

	// Start server on port 3000
	if err := app.Listen(":3000"); err != nil {
		panic("Failed to start server: " + err.Error())
	}
}

