// Global variables to store saved webhook configuration with thread safety
var (
	savedWebhookURL string
	webhookMutex    sync.RWMutex
)

// WebhookConfigRequest represents the incoming request body
type WebhookConfigRequest struct {
	WebhookURL string `json:"webhook_url"`
}

// ConfigureWebhook handles the webhook configuration request
func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Parse incoming request body
	var req WebhookConfigRequest
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(http.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"message": fmt.Sprintf("Invalid request body: %v", err),
		})
	}

	// Validate webhook URL presence
	if req.WebhookURL == "" {
		return ctx.Status(http.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"message": "webhook_url is required",
		})
	}

	// Validate URL format
	parsedURL, err := url.Parse(req.WebhookURL)
	if err != nil {
		return ctx.Status(http.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"message": fmt.Sprintf("Invalid webhook URL format: %v", err),
		})
	}

	// Validate URL scheme
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return ctx.Status(http.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"message": "webhook_url must use http or https scheme",
		})
	}

	// Validate URL host
	if parsedURL.Host == "" {
		return ctx.Status(http.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"message": "webhook_url must have a valid host",
		})
	}

	// Create HTTP client with 3-second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Send test GET request
	testResp, err := client.Get(req.WebhookURL)
	if err != nil {
		return ctx.Status(http.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"message": fmt.Sprintf("Failed to send test request: %v", err),
		})
	}
	// Ensure response body is closed to prevent resource leaks
	defer testResp.Body.Close()

	// Check for successful test response (2xx status code)
	if testResp.StatusCode < 200 || testResp.StatusCode >= 300 {
		return ctx.Status(http.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"message": fmt.Sprintf("Test request returned non-success status: %d", testResp.StatusCode),
		})
	}

	// Save the webhook configuration with thread safety
	webhookMutex.Lock()
	savedWebhookURL = req.WebhookURL
	webhookMutex.Unlock()

	// Return success response
	return ctx.Status(http.StatusOK).JSON(fiber.Map{
		"success": true,
		"message": "Webhook configured successfully",
		"data": fiber.Map{
			"webhook_url": req.WebhookURL,
		},
	})
}

func main() {
	// Initialize Fiber app
	app := fiber.New()

	// Register endpoints
	app.Post("/configure-webhook", ConfigureWebhook)

	// Optional: Endpoint to retrieve current webhook configuration
	app.Get("/webhook", func(ctx *fiber.Ctx) error {
		webhookMutex.RLock()
		defer webhookMutex.RUnlock()
		return ctx.JSON(fiber.Map{
			"success":     true,
			"webhook_url": savedWebhookURL,
		})
	})

	// Start server on port 3000
	if err := app.Listen(":3000"); err != nil {
		panic(fmt.Sprintf("Failed to start server: %v", err))
	}
}

