var privateIPBlocks []*net.IPNet

func init() {
	// Define private, loopback, link-local, and unique local CIDR ranges
	for _, cidr := range []string{
		"127.0.0.0/8",    // IPv4 loopback
		"10.0.0.0/8",     // RFC1918 private address range
		"172.16.0.0/12",  // RFC1918 private address range
		"192.168.0.0/16", // RFC1918 private address range
		"169.254.0.0/16", // RFC3927 link-local address range
		"::1/128",         // IPv6 loopback
		"fe80::/10",       // IPv6 link-local address range
		"fc00::/7",        // IPv6 unique local address range
	} {
		_, block, err := net.ParseCIDR(cidr)
		if err!= nil {
			panic(fmt.Sprintf("failed to parse CIDR %q: %v", cidr, err))
		}
		privateIPBlocks = append(privateIPBlocks, block)
	}
}

// isPrivateIP checks if an IP address is in a restricted range (private, loopback, link-local)
func isPrivateIP(ip net.IP) bool {
	if ip == nil {
		return true
	}
	for _, block := range privateIPBlocks {
		if block.Contains(ip) {
			return true
		}
	}
	return false
}

// validateWebhookURL performs SSRF and additional security checks on the parsed URL
func validateWebhookURL(parsedURL *url.URL) error {
	// Extract host without port
	host := parsedURL.Host
	// Split host and port if present
	if h, _, err := net.SplitHostPort(host); err == nil {
		host = h
	}
	// Resolve host to IP addresses to check for private ranges
	ips, err := net.LookupIP(host)
	if err!= nil {
		return fmt.Errorf("could not resolve host: %w", err)
	}
	// Check each resolved IP address
	for _, ip := range ips {
		if isPrivateIP(ip) {
			return errors.New("cannot target private, loopback, or link-local addresses")
		}
	}
	return nil
}

// webhookRequest represents the expected JSON request body
type webhookRequest struct {
	WebhookURL string `json:"webhook_url"`
}

// ConfigureWebhook handles POST requests to configure a webhook URL
func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Parse the JSON request body
	var req webhookRequest
	if err := ctx.BodyParser(&req); err!= nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Invalid JSON format",
		})
	}

	// Validate that webhook_url is provided
	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook_url is required",
		})
	}

	// Validate URL format
	parsedURL, err := url.ParseRequestURI(req.WebhookURL)
	if err!= nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Invalid webhook URL format",
		})
	}

	// Ensure the URL has a valid scheme
	if parsedURL.Scheme!= "http" && parsedURL.Scheme!= "https" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook URL must use http or https scheme",
		})
	}

	// Disallow user credentials in the URL
	if parsedURL.User!= nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook URL must not include user credentials",
		})
	}

	// Perform SSRF and network validation
	if err := validateWebhookURL(parsedURL); err!= nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   fmt.Sprintf("Invalid webhook URL: %v", err),
		})
	}

	// Create a custom HTTP client with timeout and no redirect following
	client := &http.Client{
		Timeout: 3 * time.Second,
		CheckRedirect: func(req *http.Request, via []*http.Request) error {
			// Do not follow redirects to prevent SSRF via redirect chains
			return http.ErrUseLastResponse
		},
	}

	// Send test GET request to webhook URL (as per requirement)
	resp, err := client.Get(req.WebhookURL)
	if err!= nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   fmt.Sprintf("Failed to send test request to webhook URL: %v", err),
		})
	}
	defer resp.Body.Close()

	// Check if the webhook responded successfully (2xx status)
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   fmt.Sprintf("Webhook URL returned non-success status: %d", resp.StatusCode),
		})
	}

	// Save the configuration
	// db.SaveWebhookURL(req.WebhookURL) // Assume db is a predefined database instance

	// Return success response
	return ctx.Status(fiber.StatusOK).JSON(fiber.Map{
		"success": true,
		"message": "Webhook configured successfully",
	})
}

