package main

import (
	"net/http"
	"sync"
	"time"

	"github.com/gofiber/fiber/v2"
)

// Global variables to store the saved webhook URL with mutex for concurrent access
var (
	savedWebhookURL string
	webhookMutex    sync.RWMutex
)

// ConfigureWebhookRequest represents the incoming JSON request body
type ConfigureWebhookRequest struct {
	WebhookURL string `json:"webhook_url"`
}

// WebhookResponse represents the JSON response returned to the client
type WebhookResponse struct {
	Success bool   `json:"success"`
	Message string `json:"message,omitempty"`
	Error   string `json:"error,omitempty"`
}

// ConfigureWebhook handles the POST request to configure and validate a webhook URL
func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Parse the incoming JSON request body
	var req ConfigureWebhookRequest
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookResponse{
			Success: false,
			Error:   "Invalid request body: " + err.Error(),
		})
	}

	// Validate that webhook_url is provided
	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookResponse{
			Success: false,
			Error:   "webhook_url is required",
		})
	}

	// Create HTTP client with 3-second timeout as required
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Create test GET request using the request's context for cancellation propagation
	testReq, err := http.NewRequestWithContext(ctx.Context(), http.MethodGet, req.WebhookURL, nil)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookResponse{
			Success: false,
			Error:   "Invalid webhook URL format: " + err.Error(),
		})
	}

	// Set a descriptive User-Agent header for the test request
	testReq.Header.Set("User-Agent", "Fiber-Webhook-Configurator/1.0")

	// Send the test request
	resp, err := client.Do(testReq)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookResponse{
			Success: false,
			Error:   "Failed to validate webhook URL: " + err.Error(),
		})
	}
	// Ensure the response body is closed to prevent resource leaks
	defer resp.Body.Close()

	// Save the validated webhook URL with thread-safe access
	webhookMutex.Lock()
	savedWebhookURL = req.WebhookURL
	webhookMutex.Unlock()

	// Return success response
	return ctx.Status(fiber.StatusOK).JSON(WebhookResponse{
		Success: true,
		Message: "Webhook configured and validated successfully",
	})
}

func main() {
	// Initialize a new Fiber app
	app := fiber.New()

	// Register the ConfigureWebhook handler for POST requests
	app.Post("/configure-webhook", ConfigureWebhook)

	// Optional: Add a GET endpoint to verify the currently saved webhook URL (for testing purposes)
	app.Get("/current-webhook", func(c *fiber.Ctx) error {
		webhookMutex.RLock()
		url := savedWebhookURL
		webhookMutex.RUnlock()
		return c.JSON(fiber.Map{"saved_webhook_url": url})
	})

	// Start the server on port 3000
	app.Listen(":3000")
}

