// Global in-memory storage for webhook configuration with mutex for thread safety
var (
	savedConfig struct {
		sync.RWMutex
		webhookURL string
	}
)

// ConfigureWebhookRequest represents the incoming JSON request body
type ConfigureWebhookRequest struct {
	WebhookURL string `json:"webhook_url"`
}

// ConfigureWebhookResponse represents the outgoing JSON response
type ConfigureWebhookResponse struct {
	Success  bool   `json:"success"`
	Message  string `json:"message"`
	SavedURL string `json:"saved_url,omitempty"`
}

// ConfigureWebhook handles the webhook configuration POST request
func ConfigureWebhook(ctx *fiber.Ctx) error {
	var req ConfigureWebhookRequest

	// Parse incoming JSON body
	if err := ctx.BodyParser(&req); err!= nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(ConfigureWebhookResponse{
			Success: false,
			Message: "Invalid request body: " + err.Error(),
		})
	}

	// Validate required field
	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(ConfigureWebhookResponse{
			Success: false,
			Message: "webhook_url is required",
		})
	}

	// Validate URL format and scheme
	parsedURL, err := url.ParseRequestURI(req.WebhookURL)
	if err!= nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(ConfigureWebhookResponse{
			Success: false,
			Message: "Invalid webhook URL: " + err.Error(),
		})
	}

	if parsedURL.Scheme!= "http" && parsedURL.Scheme!= "https" {
		return ctx.Status(fiber.StatusBadRequest).JSON(ConfigureWebhookResponse{
			Success: false,
			Message: "Webhook URL must use http or https scheme",
		})
	}

	// Create HTTP client with 3-second timeout as required
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Create test GET request using fiber's context for propagation
	testReq, err := http.NewRequestWithContext(ctx.Context(), http.MethodGet, req.WebhookURL, nil)
	if err!= nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(ConfigureWebhookResponse{
			Success: false,
			Message: "Failed to create test request: " + err.Error(),
		})
	}

	// Send test request
	resp, err := client.Do(testReq)
	if err!= nil {
		return ctx.Status(fiber.StatusUnprocessableEntity).JSON(ConfigureWebhookResponse{
			Success: false,
			Message: "Test request failed: " + err.Error(),
		})
	}
	// Ensure response body is closed to prevent resource leaks
	defer resp.Body.Close()

	// Check for 2xx status code
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusUnprocessableEntity).JSON(ConfigureWebhookResponse{
			Success: false,
			Message: "Test request returned non-success status: " + resp.Status,
		})
	}

	// Save the validated webhook URL with thread-safe lock
	savedConfig.Lock()
	savedConfig.webhookURL = req.WebhookURL
	savedConfig.Unlock()

	// Return success response
	return ctx.Status(fiber.StatusOK).JSON(ConfigureWebhookResponse{
		Success:  true,
		Message:  "Webhook configured and tested successfully",
		SavedURL: req.WebhookURL,
	})
}

func main() {
	// Initialize Fiber app
	app := fiber.New()

	// Register the webhook configuration endpoint
	app.Post("/configure-webhook", ConfigureWebhook)

	// Start server on port 3000
	if err := app.Listen(":3000"); err!= nil {
		panic("Failed to start server: " + err.Error())
	}
}

