package main

import (
	"net/http"
	"net/url"
	"sync"
	"time"

	"github.com/gofiber/fiber/v2"
)

// WebhookConfigRequest represents the incoming JSON request body
type WebhookConfigRequest struct {
	WebhookURL string `json:"webhook_url"`
}

// WebhookResponse represents the JSON response sent back to the client
type WebhookResponse struct {
	Success    bool    `json:"success"`
	Message    string  `json:"message"`
	SavedURL   *string `json:"saved_url,omitempty"`
	TestStatus int     `json:"test_status,omitempty"`
}

// In-memory storage for the saved webhook URL with mutex for concurrency safety
var (
	savedWebhookURL string
	mu              sync.RWMutex
)

// ConfigureWebhook handles the webhook configuration POST request
func ConfigureWebhook(ctx *fiber.Ctx) error {
	var req WebhookConfigRequest

	// Parse the request body into the struct
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(http.StatusBadRequest).JSON(WebhookResponse{
			Success: false,
			Message: "Invalid request body: " + err.Error(),
		})
	}

	// Validate required field
	if req.WebhookURL == "" {
		return ctx.Status(http.StatusBadRequest).JSON(WebhookResponse{
			Success: false,
			Message: "webhook_url is a required field",
		})
	}

	// Validate URL format and scheme
	parsedURL, err := url.Parse(req.WebhookURL)
	if err != nil || (parsedURL.Scheme != "http" && parsedURL.Scheme != "https") {
		return ctx.Status(http.StatusBadRequest).JSON(WebhookResponse{
			Success: false,
			Message: "Invalid webhook URL: must be a valid http/https URL",
		})
	}

	// Create HTTP client with 3-second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Send test GET request
	resp, err := client.Get(req.WebhookURL)
	if err != nil {
		return ctx.Status(http.StatusOK).JSON(WebhookResponse{
			Success: false,
			Message: "Test request failed: " + err.Error(),
		})
	}
	defer resp.Body.Close()

	// Save the valid webhook URL safely
	mu.Lock()
	savedWebhookURL = req.WebhookURL
	mu.Unlock()

	// Return success response
	return ctx.JSON(WebhookResponse{
		Success:    true,
		Message:    "Webhook configured successfully",
		SavedURL:   &req.WebhookURL,
		TestStatus: resp.StatusCode,
	})
}

func main() {
	// Initialize Fiber app
	app := fiber.New()

	// Register the webhook configuration endpoint
	app.Post("/configure-webhook", ConfigureWebhook)

	// Optional: Endpoint to check current webhook configuration
	app.Get("/webhook-status", func(ctx *fiber.Ctx) error {
		mu.RLock()
		defer mu.RUnlock()

		if savedWebhookURL == "" {
			return ctx.JSON(WebhookResponse{
				Success: false,
				Message: "No webhook configured yet",
			})
		}

		return ctx.JSON(WebhookResponse{
			Success:  true,
			Message:  "Current webhook configuration",
			SavedURL: &savedWebhookURL,
		})
	})

	// Start server on port 3000
	app.Listen(":3000")
}

