package main

import (
	"fmt"
	"log"
	"net/http"
	"sync"
	"time"

	"github.com/gofiber/fiber/v2"
)

var (
	savedWebhookURL string
	webhookMutex    sync.RWMutex
)

// WebhookRequest represents the incoming request body
type WebhookRequest struct {
	WebhookURL string `json:"webhook_url"`
}

// WebhookResponse represents the JSON response
type WebhookResponse struct {
	Success bool        `json:"success"`
	Message string      `json:"message"`
	Data    interface{} `json:"data,omitempty"`
}

// ConfigureWebhook handles the webhook configuration request
func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Parse request body
	var req WebhookRequest
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookResponse{
			Success: false,
			Message: fmt.Sprintf("Invalid request body: %v", err),
		})
	}

	// Validate webhook URL is present
	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookResponse{
			Success: false,
			Message: "webhook_url is required",
		})
	}

	// Create HTTP client with 3-second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Send test GET request
	resp, err := client.Get(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookResponse{
			Success: false,
			Message: fmt.Sprintf("Failed to validate webhook URL: %v", err),
		})
	}
	defer resp.Body.Close()

	// Check for successful status code
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookResponse{
			Success: false,
			Message: fmt.Sprintf("Webhook URL returned non-success status code: %d", resp.StatusCode),
		})
	}

	// Save the webhook configuration
	webhookMutex.Lock()
	savedWebhookURL = req.WebhookURL
	webhookMutex.Unlock()

	// Return success response
	return ctx.JSON(WebhookResponse{
		Success: true,
		Message: "Webhook configured successfully",
		Data: map[string]string{
			"webhook_url": req.WebhookURL,
		},
	})
}

func main() {
	app := fiber.New()

	// Register the configure webhook endpoint
	app.Post("/configure-webhook", ConfigureWebhook)

	// Start the server on port 3000
	log.Fatal(app.Listen(":3000"))
}

